INSERT INTO `quest_offer_reward` (`ID`, `Emote1`, `Emote2`, `Emote3`, `Emote4`, `EmoteDelay1`, `EmoteDelay2`, `EmoteDelay3`, `EmoteDelay4`, `RewardText`, `VerifiedBuild`) VALUES
(26393, 1, 0, 0, 0, 0, 0, 0, 0, 'You have to get this note to Stormwind?  That\'s not a problem, you can take one of my gryphons!', 57564), -- 26393
(2158, 2, 0, 0, 0, 0, 0, 0, 0, 'Rest and relaxation for the tired and cold -- that\'s our motto! Please, take a seat by the fire and rest your weary bones.$B$BWould you like to try a sampling of some of our fine food and drink?', 57564), -- 2158
(54, 1, 66, 0, 0, 0, 1000, 0, 0, 'Well, it says here that you\'ve been awarded Acting Deputy Status with the Stormwind Marshals.  Congratulations.$B$BAnd good luck - keeping Elwynn safe is no picnic... what with most the army busy doing who knows what for who knows which noble!$B$BIt\'s hard to keep track of politics in these dark days...', 57564), -- 54
(26390, 396, 5, 0, 0, 0, 0, 0, 0, 'With Kurtok slain we are safe once again from the orcish hordes. I will send peasants to the pass in an attempt to seal the passage so that no more orcs may come through into our territory.$B$BYou have the thanks of Stormwind and of the Alliance, hero!', 57564), -- 26390
(26389, 4, 0, 0, 0, 0, 0, 0, 0, 'The Blackrock orcs will surely fall now that their main force has been defeated! Only one task remains.', 57564), -- 26389
(26391, 1, 5, 0, 0, 0, 0, 0, 0, 'Bless your heart, $N. You truly are a hero of the Alliance! Though the land is completely incinerated and there is nothing left of the vineyard but ash and debris, I still might be able to recover. Right? How bad can it be?', 57564), -- 26391
(28823, 1, 1, 1, 5, 0, 0, 0, 0, 'With your help we have managed to secure the northern and western sectors of Northshire. We still have a rather large contingency of Blackrock orcs to the east and they\'ve begun burning down the forest!', 57564), -- 28823
(28797, 0, 0, 0, 0, 0, 0, 0, 0, 'That will teach those monsters! They\'ll think twice before taking another mercenary job for orcs.', 57564), -- 28797
(28813, 273, 4, 0, 0, 0, 0, 0, 0, 'I think you now understand the power of the Light. The Light giveth hope, $g brother:sister; and the Light taketh from the darkness! BLESSED BE THE LIGHT!', 57564), -- 28813
(28789, 0, 0, 0, 0, 0, 0, 0, 0, 'It\'s true, we were ambushed. I don\'t dare send any more soldiers out there and risk losing them too. I need a volunteer. Someone willing to risk their life!', 57564), -- 28789
(26913, 1, 0, 0, 0, 0, 0, 0, 0, 'You\'re a quick learner, $N. Return to me as you grow stronger and I\'ll show you other combat techniques.', 57564), -- 26913
(3100, 1, 1, 0, 0, 0, 0, 0, 0, 'Get yourself squared away, learn the layout of the land, and come back to me whenever you need training. I\'ll be here night or day.$B$BThe Knights of the Silver Hand have done well in making this place fairly safe, but as you meet the other citizens, I think you\'ll find they all have problems they could use some help with--help a warrior can give them. Good luck.', 57564), -- 3100
(28774, 21, 1, 5, 0, 0, 0, 0, 0, 'Excellent work, $N. You\'ve turned out to be quite an asset to this garrison. It\'s time for you to train!', 57564), -- 28774
(28766, 1, 1, 0, 0, 0, 0, 0, 0, 'You\'ve bought us a little time, $N, but we\'ve got even bigger problems to deal with now.', 57564); -- 28766
